18.     internal readonly struct DiagnosticScope : IDisposable
19.     {
20.         private const string AzureSdkScopeLabel = "az.sdk.scope";
21.         internal const string OpenTelemetrySchemaAttribute = "az.schema_url";
22. 
23.         // we follow OpenTelemtery Semantic Conventions 1.23.0
24.         // https://github.com/open-telemetry/semantic-conventions/blob/v1.23.0
25.         internal const string OpenTelemetrySchemaVersion = "https://opentelemetry.io/schemas/1.23.0";
26.         private static readonly object AzureSdkScopeValue = bool.TrueString;
27.         private readonly ActivityAdapter? _activityAdapter;
28.         private readonly bool _suppressNestedClientActivities;
29. 
30.         internal DiagnosticScope(string scopeName, DiagnosticListener source, object? diagnosticSourceArgs, ActivitySource? activitySource, System.Diagnostics.ActivityKind kind, bool suppressNestedClientActivities)
31.         {
32.             // ActivityKind.Internal and Client both can represent public API calls depending on the SDK
33.             _suppressNestedClientActivities = (kind == ActivityKind.Client || kind == System.Diagnostics.ActivityKind.Internal) ? suppressNestedClientActivities : false;
34. 
35.             // outer scope presence is enough to suppress any inner scope, regardless of inner scope configuation.
36.             bool hasListeners;
37.             hasListeners = activitySource?.HasListeners() ?? false;
38.             IsEnabled = source.IsEnabled() || hasListeners;
39. 
40.             if (_suppressNestedClientActivities)
41.             {
42.                 IsEnabled &= !AzureSdkScopeValue.Equals(Activity.Current?.GetCustomProperty(AzureSdkScopeLabel));
43.             }
44. 
45.             _activityAdapter = IsEnabled ? new ActivityAdapter(
46.                                                     activitySource: activitySource,
47.                                                     diagnosticSource: source,
48.                                                     activityName: scopeName,
49.                                                     kind: kind,
50.                                                     diagnosticSourceArgs: diagnosticSourceArgs) : null;
51.         }
52. 
53.         public bool IsEnabled { get; }
54. 
55.         public void AddAttribute(string name, string? value)
56.         {
57.             if (value != null)
58.             {
59.                 _activityAdapter?.AddTag(name, value);
60.             }
61.         }
62. 
63.         public void AddIntegerAttribute(string name, int value)
64.         {
65.             _activityAdapter?.AddTag(name, value);
66.         }
67. 
68.         public void AddLongAttribute(string name, long value)
69.         {
70.             _activityAdapter?.AddTag(name, value);
71.         }
72. 
73.         public void AddAttribute<T>(string name, T value, Func<T, string> format)
74.         {
75.             if (_activityAdapter != null && value != null)
76.             {
77.                 var formattedValue = format(value);
78.                 _activityAdapter.AddTag(name, formattedValue);
79.             }
80.         }
81. 
82.         /// <summary>
83.         /// Adds a link to the scope. This must be called before <see cref="Start"/> has been called for the DiagnosticScope.
84.         /// </summary>
85.         /// <param name="traceparent">The traceparent for the link.</param>
86.         /// <param name="tracestate">The tracestate for the link.</param>
87.         /// <param name="attributes">Optional attributes to associate with the link.</param>
88.         public void AddLink(string traceparent, string? tracestate, IDictionary<string, object?>? attributes = null)
89.         {
90.             _activityAdapter?.AddLink(traceparent, tracestate, attributes);
91.         }
