94.         {
95.             Activity? started = _activityAdapter?.Start();
96.             if (_suppressNestedClientActivities)
97.             {
98.                 started?.SetCustomProperty(AzureSdkScopeLabel, AzureSdkScopeValue);
99.             }
100.         }
101. 
102.         public void SetDisplayName(string displayName)
103.         {
104.             _activityAdapter?.SetDisplayName(displayName);
105.         }
106. 
