129.         /// Marks the scope as failed.
130.         /// </summary>
131.         /// <param name="exception">The exception to associate with the failed scope.</param>
132.         public void Failed(Exception exception)
133.         {
134.             if (exception is RequestFailedException requestFailedException)
135.             {
