157.         private class DiagnosticActivity : Activity
158.         {
159. #pragma warning disable 109 // extra new modifier
160.             public new IEnumerable<Activity> Links { get; set; } = Array.Empty<Activity>();
161. #pragma warning restore 109
162. 
163.             public DiagnosticActivity(string operationName) : base(operationName)
164.             {
165.             }
166.         }
167. 
168.         private class ActivityAdapter : IDisposable
169.         {
170.             private readonly ActivitySource? _activitySource;
171.             private readonly DiagnosticSource _diagnosticSource;
172.             private readonly string _activityName;
173.             private readonly System.Diagnostics.ActivityKind _kind;
174.             private readonly object? _diagnosticSourceArgs;
175. 
176.             private Activity? _currentActivity;
177.             private Activity? _sampleOutActivity;
178. 
179.             private ActivityTagsCollection? _tagCollection;
180.             private DateTimeOffset _startTime;
181.             private List<ActivityLink>? _links;
182.             private string? _traceparent;
183.             private string? _tracestate;
184.             private string? _displayName;
185. 
186.             public ActivityAdapter(ActivitySource? activitySource, DiagnosticSource diagnosticSource, string activityName, System.Diagnostics.ActivityKind kind, object? diagnosticSourceArgs)
187.             {
188.                 _activitySource = activitySource;
189.                 _diagnosticSource = diagnosticSource;
190.                 _activityName = activityName;
191.                 _kind = kind;
192.                 _diagnosticSourceArgs = diagnosticSourceArgs;
193.             }
194. 
195.             public void AddTag(string name, object value)
196.             {
197.                 if (_sampleOutActivity == null)
198.                 {
199.                     if (_currentActivity == null)
200.                     {
201.                         // Activity is not started yet, add the value to the collection
202.                         // that is going to be passed to StartActivity
203.                         _tagCollection ??= new ActivityTagsCollection();
204.                         _tagCollection[name] = value!;
205.                     }
206.                     else
207.                     {
208.                         AddObjectTag(name, value);
209.                     }
210.                 }
211.             }
212. 
213.             private IReadOnlyList<Activity> GetDiagnosticSourceLinkCollection()
214.             {
215.                 if (_links == null)
216.                 {
217.                     return Array.Empty<Activity>();
218.                 }
219. 
220.                 var linkCollection = new List<Activity>();
221. 
222.                 foreach (var link in _links)
223.                 {
224.                     var activity = new Activity("LinkedActivity");
225.                     activity.SetIdFormat(ActivityIdFormat.W3C);
226.                     if (link.Context != default)
227.                     {
228.                         activity.SetParentId(ActivityContextToTraceParent(link.Context));
229.                         activity.TraceStateString = link.Context.TraceState;
230.                     }
231. 
232.                     if (link.Tags != null)
233.                     {
234.                         foreach (var tag in link.Tags)
235.                         {
236.                             if (tag.Value != null)
237.                             {
238.                                 // old code path, only string attributes are supported
239.                                 activity.AddTag(tag.Key, tag.Value.ToString());
240.                             }
241.                         }
242.                     }
243.                     linkCollection.Add(activity);
244.                 }
245. 
246.                 return linkCollection;
247.             }
248. 
249.             private static string ActivityContextToTraceParent(ActivityContext context)
250.             {
251.                 string flags = (context.TraceFlags == ActivityTraceFlags.None) ? "00" : "01";
252.                 return "00-" + context.TraceId + "-" + context.SpanId + "-" + flags;
253.             }
254. 
255.             public void AddLink(string traceparent, string? tracestate, IDictionary<string, object?>? attributes)
256.             {
257.                 // if context is invalid, we should still add a link since it contains attributes
258.                 // so we let ActivityLink deal with the default context.
259.                 // This is otel spec requirement and default context is allowed on links.
260.                 ActivityContext.TryParse(traceparent, tracestate, out var context);
261.                 var linkedActivity = new ActivityLink(context, attributes == null ? null : new ActivityTagsCollection(attributes));
262.                 _links ??= new List<ActivityLink>();
263.                 _links.Add(linkedActivity);
264.             }
265. 
266.             public Activity? Start()
267.             {
268.                 _currentActivity = StartActivitySourceActivity();
269.                 if (_currentActivity != null)
270.                 {
271.                     if (!_currentActivity.IsAllDataRequested)
272.                     {
273.                         _sampleOutActivity = _currentActivity;
274.                         _currentActivity = null;
275. 
276.                         return null;
277.                     }
278. 
279.                     _currentActivity.SetTag(OpenTelemetrySchemaAttribute, OpenTelemetrySchemaVersion);
280.                 }
281.                 else
282.                 {
283.                     if (!_diagnosticSource.IsEnabled(_activityName, _diagnosticSourceArgs))
284.                     {
285.                         return null;
286.                     }
287. 
288.                     switch (_kind)
289.                     {
290.                         case ActivityKind.Internal:
291.                             AddTag("kind", "internal");
292.                             break;
293.                         case ActivityKind.Server:
294.                             AddTag("kind", "server");
295.                             break;
296.                         case ActivityKind.Client:
297.                             AddTag("kind", "client");
298.                             break;
299.                         case ActivityKind.Producer:
300.                             AddTag("kind", "producer");
301.                             break;
302.                         case ActivityKind.Consumer:
303.                             AddTag("kind", "consumer");
304.                             break;
305.                     }
306. 
307.                     _currentActivity = new DiagnosticActivity(_activityName)
308.                     {
309.                         Links = GetDiagnosticSourceLinkCollection(),
310.                     };
311.                     _currentActivity.SetIdFormat(ActivityIdFormat.W3C);
312. 
313.                     if (_startTime != default)
314.                     {
315.                         _currentActivity.SetStartTime(_startTime.UtcDateTime);
316.                     }
317. 
318.                     if (_tagCollection != null)
319.                     {
320.                         foreach (var tag in _tagCollection)
321.                         {
322.                             AddObjectTag(tag.Key, tag.Value!);
323.                         }
324.                     }
325. 
326.                     if (_traceparent != null)
327.                     {
328.                         _currentActivity.SetParentId(_traceparent);
329.                     }
330. 
331.                     if (_tracestate != null)
332.                     {
333.                         _currentActivity.TraceStateString = _tracestate;
334.                     }
335. 
